#include<bits/stdc++.h>
using namespace std;
struct FHQ_Treap
{
    struct node
    {
        int l,r;
        int val,key;
        int siz;
    }t[200010];
    int cnt,root;
    stack<int> s;
    FHQ_Treap():cnt(0){}
    int newnode(int v)
    {
        int x=++cnt;
        t[x].l=t[x].r=0;
        t[x].val=v;
        t[x].key=rand();
        t[x].siz=1;
        return x;
    }
    void pushup(int x)
    {
        t[x].siz=t[t[x].l].siz+t[t[x].r].siz+1;
    }
    void split(int p,int v,int &x,int &y)
    {
        if(p==0)
        {
            x=y=0;
            return;
        }
        if(t[p].val<=v)
        {
            x=p;
            split(t[x].r,v,t[x].r,y);
        }
        else
        {
            y=p;
            split(t[y].l,v,x,t[y].l);
        }
        pushup(p);
    }
    int merge(int x,int y)
    {
        if(x==0||y==0)
        {
            return x+y;
        }
        if(t[x].key<t[y].key)
        {
            t[x].r=merge(t[x].r,y);
            pushup(x);
            return x;
        }
        else
        {
            t[y].l=merge(x,t[y].l);
            pushup(y);
            return y;
        }
    }
    void insert(int v)
    {
        int x,y,z;
        split(root,v,x,y);
        z=newnode(v);
        root=merge(merge(x,z),y);
    }
    void del(int v)
    {
        int x,y,z;
        split(root,v,x,z);
        split(x,v-1,x,y);
        y=merge(t[y].l,t[y].r);
        root=merge(merge(x,y),z);
    }
    int getrnk(int v)
    {
        int x,y;
        split(root,v-1,x,y);
        int ans=t[x].siz+1;
        root=merge(x,y);
        return ans;
    }
    int kth(int x,int k)
    {
        if(k==t[t[x].l].siz+1)
        {
            return x;
        }
        if(k<=t[t[x].l].siz)
        {
            return kth(t[x].l,k);
        }
        else
        {
            return kth(t[x].r,k-t[t[x].l].siz-1);
        }
    }
    int getkth(int x)
    {
        return t[kth(root,x)].val;
    }
    int getpre(int x)
    {
        int pos=getrnk(x);
        if(pos==1)
        {
            return -2147483647;
        }
        return getkth(pos-1);
    }
    int getnxt(int x)
    {
        int pos=getrnk(x+1);
        if(pos>t[root].siz)
        {
            return 2147483647;
        }
        return getkth(pos);
    }
}t;
int main()
{
    int n;
    scanf("%d",&n);
    while(n--)
    {
        int op,x;
        scanf("%d%d",&op,&x);
        if(op==1)
        {
            printf("%d\n",t.getrnk(x));
        }
        else if(op==2)
        {
            printf("%d\n",t.getkth(x));
        }
        else if(op==3)
        {
            printf("%d\n",t.getpre(x));
        }
        else if(op==4)
        {
            printf("%d\n",t.getnxt(x));
        }
        else
        {
            t.insert(x);
        }
    }
    return 0;
}
